import { By } from "selenium-webdriver";
import ojwd, { DriverLike, register } from "../../";
import { OjTreemap } from "./OjTreemap";
export { OjTreemap };

/**
 * Create an instance of [[OjTreemap]].  This function will first wait for
 * the element to appear in the DOM before trying to locate it.
 * @example
 * <code>
 * const el = await ojTreemap(driver, By.id('my-oj-treemap'))
 * </code>
 * @param driver A WebDriver/WebElement instance used to locate the component
 * element.
 * @param by The By locator with which to find the element
 */
export async function ojTreemap(driver: DriverLike, by: By): Promise<OjTreemap> {
  const webEl = await driver.findElement(by);
  // Check that the element is of type OjTreemap
  if (!(webEl instanceof OjTreemap)) {
    const tagName = await webEl.getTagName();
    throw Error(`Locator '${by}' located a <${tagName}>, but expected <oj-treemap>`);
  }
  return webEl;
}

register("oj-treemap", OjTreemap);
